 complete end-to-end example:
```
import LiteRTLMSwift

// 1. Download model (~2.6 GB, only needed once)
 let downloader = ModelDownloader ( ) 
 try await downloader . download ( )  // defaults to Gemma 4 E2B from HuggingFace

// 2. Load engine
 let engine = LiteRTLMEngine ( modelPath : downloader . modelPath ) 
 try await engine . load ( )  // takes ~5-10s on first launch

// 3. Generate text
 let response = try await engine . generate ( 
    prompt : " <|turn>user \n What is Swift? \n <turn|> \n <|turn>model \n " , 
    temperature : 0.7 , 
    maxTokens : 256 
 ) 
 print ( response ) 

// 4. Vision (image understanding)
 let imageData = try Data ( contentsOf : photoURL ) 
 let caption = try await engine . vision ( 
    imageData : imageData ,  // JPEG, PNG, or HEIC
    prompt : " Describe this photo. " , 
    maxTokens : 512 
 ) 
 print ( caption ) 

// 5. Audio (speech/sound understanding)
 let audioData = try Data ( contentsOf : audioURL ) 
 let transcript = try await engine . audio ( 
    audioData : audioData ,  // WAV, FLAC, or MP3
    prompt : " Transcribe this audio. " , 
    maxTokens : 512 
 ) 
 print ( transcript )
```
> **Important:** Text generation ( `generate` , `generateStreaming` , `openSession` ) requires Gemma 4's turn marker format in the prompt (see Prompt Format ). All other methods — vision, audio, multimodal, and the persistent conversation API ( `openConversation` / `conversationSend` ) — take plain text prompts.

